-- Oracle HR Schema — Oracle's classic Human Resources sample database
-- 7 tables: REGIONS, COUNTRIES, LOCATIONS, DEPARTMENTS, JOBS, EMPLOYEES, JOB_HISTORY
-- Source: https://docs.oracle.com/en/database/oracle/oracle-database/21/comsc/
-- Note: APP_USER=hr is set in docker-compose, this script runs as hr

-- ============================================================================
-- REGIONS
-- ============================================================================
CREATE TABLE REGIONS (
    REGION_ID   NUMBER(2)    CONSTRAINT REGION_ID_NN  NOT NULL,
    REGION_NAME VARCHAR2(25),
    CONSTRAINT REGION_ID_PK PRIMARY KEY (REGION_ID)
);

-- ============================================================================
-- COUNTRIES
-- ============================================================================
CREATE TABLE COUNTRIES (
    COUNTRY_ID   CHAR(2)      CONSTRAINT COUNTRY_ID_NN NOT NULL,
    COUNTRY_NAME VARCHAR2(40),
    REGION_ID    NUMBER,
    CONSTRAINT  COUNTRY_C_ID_PK  PRIMARY KEY (COUNTRY_ID),
    CONSTRAINT  COUNTR_REG_FK    FOREIGN KEY (REGION_ID) REFERENCES REGIONS(REGION_ID)
);

-- ============================================================================
-- LOCATIONS
-- ============================================================================
CREATE TABLE LOCATIONS (
    LOCATION_ID    NUMBER(4),
    STREET_ADDRESS VARCHAR2(40),
    POSTAL_CODE    VARCHAR2(12),
    CITY           VARCHAR2(30) CONSTRAINT LOC_CITY_NN NOT NULL,
    STATE_PROVINCE VARCHAR2(25),
    COUNTRY_ID     CHAR(2),
    CONSTRAINT LOC_ID_PK    PRIMARY KEY (LOCATION_ID),
    CONSTRAINT LOC_C_ID_FK  FOREIGN KEY (COUNTRY_ID) REFERENCES COUNTRIES(COUNTRY_ID)
);
CREATE INDEX LOC_CITY_IX          ON LOCATIONS (CITY);
CREATE INDEX LOC_STATE_PROVINCE_IX ON LOCATIONS (STATE_PROVINCE);
CREATE INDEX LOC_COUNTRY_IX        ON LOCATIONS (COUNTRY_ID);

-- ============================================================================
-- DEPARTMENTS
-- ============================================================================
CREATE TABLE DEPARTMENTS (
    DEPARTMENT_ID   NUMBER(4),
    DEPARTMENT_NAME VARCHAR2(30) CONSTRAINT DEPT_NAME_NN NOT NULL,
    MANAGER_ID      NUMBER(6),
    LOCATION_ID     NUMBER(4),
    CONSTRAINT DEPT_ID_PK    PRIMARY KEY (DEPARTMENT_ID),
    CONSTRAINT DEPT_LOC_FK   FOREIGN KEY (LOCATION_ID) REFERENCES LOCATIONS(LOCATION_ID)
);
CREATE INDEX DEPT_LOCATION_IX ON DEPARTMENTS (LOCATION_ID);

-- ============================================================================
-- JOBS
-- ============================================================================
CREATE TABLE JOBS (
    JOB_ID     VARCHAR2(10),
    JOB_TITLE  VARCHAR2(35) CONSTRAINT JOB_TITLE_NN NOT NULL,
    MIN_SALARY NUMBER(6),
    MAX_SALARY NUMBER(6),
    CONSTRAINT JOB_ID_PK PRIMARY KEY (JOB_ID)
);

-- ============================================================================
-- EMPLOYEES
-- ============================================================================
CREATE TABLE EMPLOYEES (
    EMPLOYEE_ID    NUMBER(6),
    FIRST_NAME     VARCHAR2(20),
    LAST_NAME      VARCHAR2(25)  CONSTRAINT EMP_LAST_NAME_NN NOT NULL,
    EMAIL          VARCHAR2(25)  CONSTRAINT EMP_EMAIL_NN NOT NULL,
    PHONE_NUMBER   VARCHAR2(20),
    HIRE_DATE      DATE          CONSTRAINT EMP_HIRE_DATE_NN NOT NULL,
    JOB_ID         VARCHAR2(10)  CONSTRAINT EMP_JOB_NN NOT NULL,
    SALARY         NUMBER(8,2),
    COMMISSION_PCT NUMBER(2,2),
    MANAGER_ID     NUMBER(6),
    DEPARTMENT_ID  NUMBER(4),
    CONSTRAINT EMP_EMP_ID_PK     PRIMARY KEY (EMPLOYEE_ID),
    CONSTRAINT EMP_SALARY_MIN    CHECK (SALARY > 0),
    CONSTRAINT EMP_EMAIL_UK      UNIQUE (EMAIL),
    CONSTRAINT EMP_DEPT_FK       FOREIGN KEY (DEPARTMENT_ID) REFERENCES DEPARTMENTS(DEPARTMENT_ID),
    CONSTRAINT EMP_JOB_FK        FOREIGN KEY (JOB_ID)        REFERENCES JOBS(JOB_ID),
    CONSTRAINT EMP_MANAGER_FK    FOREIGN KEY (MANAGER_ID)    REFERENCES EMPLOYEES(EMPLOYEE_ID)
);
CREATE INDEX EMP_DEPARTMENT_IX ON EMPLOYEES (DEPARTMENT_ID);
CREATE INDEX EMP_JOB_IX        ON EMPLOYEES (JOB_ID);
CREATE INDEX EMP_MANAGER_IX    ON EMPLOYEES (MANAGER_ID);
CREATE INDEX EMP_NAME_IX       ON EMPLOYEES (LAST_NAME, FIRST_NAME);

-- Self-ref FK on DEPARTMENTS (manager is an employee)
ALTER TABLE DEPARTMENTS ADD CONSTRAINT DEPT_MGR_FK FOREIGN KEY (MANAGER_ID) REFERENCES EMPLOYEES(EMPLOYEE_ID);

-- ============================================================================
-- JOB_HISTORY
-- ============================================================================
CREATE TABLE JOB_HISTORY (
    EMPLOYEE_ID   NUMBER(6)   NOT NULL,
    START_DATE    DATE        NOT NULL,
    END_DATE      DATE        NOT NULL,
    JOB_ID        VARCHAR2(10) NOT NULL,
    DEPARTMENT_ID NUMBER(4),
    CONSTRAINT JHIST_EMP_ID_ST_DATE_PK PRIMARY KEY (EMPLOYEE_ID, START_DATE),
    CONSTRAINT JHIST_EMP_FK  FOREIGN KEY (EMPLOYEE_ID)   REFERENCES EMPLOYEES(EMPLOYEE_ID),
    CONSTRAINT JHIST_JOB_FK  FOREIGN KEY (JOB_ID)        REFERENCES JOBS(JOB_ID),
    CONSTRAINT JHIST_DEPT_FK FOREIGN KEY (DEPARTMENT_ID) REFERENCES DEPARTMENTS(DEPARTMENT_ID),
    CONSTRAINT JHIST_DATE_INTERVAL CHECK (END_DATE > START_DATE)
);
CREATE INDEX JHIST_JOB_IX    ON JOB_HISTORY (JOB_ID);
CREATE INDEX JHIST_EMPLOYEE_IX ON JOB_HISTORY (EMPLOYEE_ID);
CREATE INDEX JHIST_DEPARTMENT_IX ON JOB_HISTORY (DEPARTMENT_ID);

-- ============================================================================
-- VIEWS
-- ============================================================================
CREATE OR REPLACE VIEW EMP_DETAILS_VIEW AS
SELECT
    e.EMPLOYEE_ID,
    e.JOB_ID,
    e.MANAGER_ID,
    e.DEPARTMENT_ID,
    d.LOCATION_ID,
    l.COUNTRY_ID,
    e.FIRST_NAME,
    e.LAST_NAME,
    e.SALARY,
    e.COMMISSION_PCT,
    d.DEPARTMENT_NAME,
    j.JOB_TITLE,
    l.CITY,
    l.STATE_PROVINCE,
    c.COUNTRY_NAME,
    c.REGION_ID
FROM EMPLOYEES e
JOIN DEPARTMENTS d  ON e.DEPARTMENT_ID = d.DEPARTMENT_ID
JOIN JOBS j         ON e.JOB_ID        = j.JOB_ID
JOIN LOCATIONS l    ON d.LOCATION_ID   = l.LOCATION_ID
JOIN COUNTRIES c    ON l.COUNTRY_ID    = c.COUNTRY_ID;

